125	      customer: { yearsWithMHPCO: 0 },
126	      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
127	    });
128	    expect(result).toEqual({ results: [{ premium: 115 }] });
129	  });
