131	    const result = runScenario({
132	      customer: { yearsWithMHPCO: 0 },
133	      steps: [{ op: "quote", items: [{ type: "sword", cursed: true, enchantment: 5 }] }],
134	    });
135	    expect(result).toEqual({ results: [{ premium: 195 }] });
136	  });
137	  it("long-standing customer (≥2 years) gets 20% loyalty discount on sword: 100-20+10+5=95 G", () => {
138	    const result = runScenario({
139	      customer: { yearsWithMHPCO: 2 },
140	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
141	    });
142	    expect(result).toEqual({ results: [{ premium: 95 }] });
143	  });
144	  it.todo("customer with exactly 2 years → loyalty discount applies");
145	  it.todo("first insurance carries 10% surcharge on policy base");
146	  it.todo("follow-up contract (after first) gets 15% discount");
147	  it.todo("processing fee of 5 G is added to every premium");
148	
149	  // --- Rounding ---
150	  it.todo("premium rounded up in MHPCO favor (197.5 → 198 G)");
151	  it.todo("payout rounded down in MHPCO favor (350.5 → 350 G)");
152	
153	  // --- Multi-item policies and modifier scope ---
154	  it.todo("policy with cursed sword + plain amulet → 210 G (cursed applies to sword's base only)");
155	
156	  // --- Integration examples ---
157	  it.todo("newcomer with cursed sword (steel, ench 3): 0 years, no prior → 165 G");
158	  it.todo("long-standing customer's second contract (cursed sword, ench 7, 3 years) → 160 G");
159	
160	  // --- Claim processing: standard reimbursement ---
161	  it.todo("regular sword damage 500 G → payout 400 G (full minus 100 deductible)");
162	  it.todo("damage to rune (250 G insurance), damage 200 G → payout 100 G");
163	
164	  // --- Claim: high enchantment clause ---
165	  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% then deductible)");
166	
167	  // --- Claim: dragon material ---
168	  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full, then deductible)");
169	
170	  // --- Claim: enchantment + dragon combined ---
171	  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
172	  it.todo("dragon-material sword, ench exactly 8, damage 1000 G → payout 400 G");
173	
174	  // --- Deductible per damage event ---
175	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
176	
177	  // --- Multiple same-type items ---
178	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
179	  it.todo("two-sword policy: dragon attack damages both → each treated as separate damage with own deductible");
180	  it.todo("claim with more damages of a type than policy covers → CLI rejects (non-zero exit)");
181	
182	  // --- Cap exhaustion ---
183	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
184	  it.todo("cursed sword policy → cap 2000 G (based on unmodified insurance value)");
185	  it.todo("sword + 3 runes block → insurance sum 1750 G (block discount affects premium only)");
186	  it.todo("sword cap 2000 G, two claims of 1500 G each → first payout 1400 (cap 600), second payout 600 (cap 0)");
187	
