1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	export interface Scenario {
14	  customer: { yearsWithMHPCO: number };
15	  steps: QuoteStep[];
16	}
17	
18	export interface ScenarioResult {
19	  results: { premium: number }[];
20	}
21	
22	const PROCESSING_FEE = 5;
23	
24	const BASE_PRICE_BY_TYPE: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	const basePriceFor = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];
34	
35	const COMPONENT_BLOCK_SIZE = 3;
36	const COMPONENT_BLOCK_PRICE = 60;
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	
39	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
40	
41	const sumBasePrices = (items: Item[]): number =>
42	  items.reduce((s, i) => s + basePriceFor(i), 0);
43	
44	const groupByType = (items: Item[]): Map<string, Item[]> => {
45	  const map = new Map<string, Item[]>();
46	  for (const item of items) {
47	    const list = map.get(item.type) ?? [];
48	    list.push(item);
49	    map.set(item.type, list);
50	  }
51	  return map;
52	};
53	
54	const priceForComponentGroup = (group: Item[]): number =>
55	  group.length === COMPONENT_BLOCK_SIZE
56	    ? COMPONENT_BLOCK_PRICE
57	    : sumBasePrices(group);
58	
59	const componentsPremium = (components: Item[]): number =>
60	  Array.from(groupByType(components).values())
61	    .reduce((sum, group) => sum + priceForComponentGroup(group), 0);
62	
63	const itemsBasePremium = (items: Item[]): number => {
64	  const components = items.filter(isComponent);
65	  const nonComponents = items.filter((i) => !isComponent(i));
66	  return sumBasePrices(nonComponents) + componentsPremium(components);
67	};
68	
69	const CURSE_SURCHARGE_RATE = 0.5;
70	const HIGH_ENCHANTMENT_RATE = 0.3;
71	const HIGH_ENCHANTMENT_THRESHOLD = 5;
72	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
73	const LOYALTY_DISCOUNT_RATE = 0.2;
74	const LOYALTY_YEARS_THRESHOLD = 2;
75	
76	const perItemSurchargeRate = (item: Item): number =>
77	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
78	  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0);
79	
80	const itemSurcharges = (items: Item[]): number =>
81	  items.reduce((sum, item) => sum + basePriceFor(item) * perItemSurchargeRate(item), 0);
82	
83	const quotePremium = (step: QuoteStep, customer: { yearsWithMHPCO: number }): number => {
84	  const base = itemsBasePremium(step.items);
85	  const surcharges = itemSurcharges(step.items);
86	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
87	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
88	    ? base * LOYALTY_DISCOUNT_RATE
89	    : 0;
90	  const total = base + surcharges + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE;
91	  return Math.ceil(total);
92	};
93	
94	export const runScenario = (scenario: Scenario): ScenarioResult => ({
95	  results: scenario.steps.map((step) => ({ premium: quotePremium(step, scenario.customer) })),
96	});
97

